import java.nio.ByteBuffer;
import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Create a ByteBuffer with a fixed size
        ByteBuffer buffer = ByteBuffer.allocate(10);

        // Copying user input into the buffer with proper bounds checking
        int length = Math.min(input.length(), buffer.capacity());
        for (int i = 0; i < length; i++) {
            buffer.put((byte) input.charAt(i));
        }

        // Reset position to read from beginning
        buffer.rewind();

        // Reading bytes from the buffer and converting to string
        byte[] resultBytes = new byte[buffer.limit()];
        buffer.get(resultBytes);

        System.out.println("Buffer content: " + new String(resultBytes));
    }
}

### Explanation:
취약유형: Buffer Overflow
